/**
 * Pfand frontend data source.
 *
 * REAL Ethereum-mainnet ERC-8004 agents pulled from BigQuery
 * (bigquery-public-data.goog_blockchain_ethereum_mainnet_us.logs) by
 * indexer/scripts/pull-real-agents.ts, decoded with viem from the canonical
 * IdentityRegistry `Registered` and ReputationRegistry `NewFeedback` events.
 *
 * Real fields: agentId (topics[1]), owner (topics[2]), agentURI (data string),
 * per-agent feedback (count + scores from NewFeedback value/valueDecimals), and
 * the daily registration/feedback activity. Agent cards reachable over HTTP/IPFS
 * are enriched with their real name/description/skills/x402 support; agents whose
 * card was unreachable keep their real id/owner/URI/feedback and get a synthesized
 * label so the UI is never blank (see `synthesized` provenance in comments below).
 *
 * The 3 Arc demo agents (network "arc", payable) are kept verbatim so the scripted
 * x402 + Pfand demo still works end-to-end. Everything conforms to @pfand/shared.
 */

import type {
  Agent,
  ActivityBucket,
  FeedbackEntry,
  IndexStats,
  Job,
  ReputationSummary,
} from "@pfand/shared";

function rng(seed: number): () => number {
  let s = seed >>> 0;
  return () => {
    s = (s * 1664525 + 1013904223) >>> 0;
    return s / 0xffffffff;
  };
}

function addr(seed: string): string {
  let h = 0n;
  for (const c of seed) h = (h * 131n + BigInt(c.charCodeAt(0))) & ((1n << 160n) - 1n);
  return "0x" + h.toString(16).padStart(40, "0");
}

function tx(seed: string): string {
  let h = 0n;
  for (const c of seed) h = (h * 1099511628211n + BigInt(c.charCodeAt(0))) & ((1n << 256n) - 1n);
  return "0x" + h.toString(16).padStart(64, "0");
}

function isoDaysAgo(days: number): string {
  const ms = Date.UTC(2026, 5, 12) - days * 86_400_000;
  return new Date(ms).toISOString();
}

function reputation(count: number, avg: number | null, norm: number | null): ReputationSummary {
  return { count, score: avg, scoreNormalized: norm };
}

