const ARC_TAGS1 = ["accuracy", "latency", "value", "reliability", "ux"];
const ARC_TAGS2 = ["verified-job", "repeat-client", "first-job", "escrowed", "x402"];

function buildArcFeedback(spec: ArcSpec): FeedbackEntry[] {
  if (spec.avg === null || spec.fbCount === 0) return [];
  const r = rng(spec.id * 7919 + 13);
  const n = Math.min(spec.fbCount, 16);
  const out: FeedbackEntry[] = [];
  for (let i = 0; i < n; i++) {
    const jitter = (r() - 0.5) * 24;
    const raw = Math.max(0, Math.min(100, Math.round(spec.avg + jitter)));
    const revoked = r() < 0.05;
    const day = Math.round((i / n) * spec.ageDays);
    out.push({
      agentId: String(spec.id),
      network: "arc",
      client: addr(`${spec.slug}-client-${i}`),
      feedbackIndex: i,
      value: raw * 100,
      valueDecimals: 2,
      score: raw,
      tag1: ARC_TAGS1[Math.floor(r() * ARC_TAGS1.length)]!,
      tag2: ARC_TAGS2[Math.floor(r() * ARC_TAGS2.length)]!,
      feedbackURI: `ipfs://bafy${spec.slug}feedback${i}`,
      isRevoked: revoked,
      txHash: tx(`${spec.slug}-fb-${i}`),
      blockNumber: 21_400_000 + spec.id * 1000 + i,
      timestamp: isoDaysAgo(spec.ageDays - day),
    });
  }
  return out.reverse();
}

function buildArcAgent(spec: ArcSpec): Agent {
  const owner = addr(`${spec.slug}-owner`);
  return {
    agentId: String(spec.id),
    network: "arc",
    owner,
    agentURI: `https://${spec.slug}.broker8004.eth/.well-known/agent.json`,
    name: spec.name,
    description: spec.description,
    image: null,
    skills: spec.skills,
    domains: spec.domains,
    x402Support: spec.x402,
    serviceEndpoint: `https://api.${spec.slug}.xyz/v1/invoke`,
    payToWallet: addr(`${spec.slug}-wallet`),
    ensName: `${spec.slug}.broker8004.eth`,
    payable: true,
    priceUsdc: spec.price,
    reputation: reputation(spec.fbCount, spec.avg, spec.avg === null ? null : Math.round(spec.avg)),
    createdAtBlock: 21_000_000 + spec.id * 137,
    createdAt: isoDaysAgo(spec.ageDays),
  };
}

const ARC_AGENTS: Agent[] = ARC_SPECS.map(buildArcAgent);
const ARC_FEEDBACK: Record<string, FeedbackEntry[]> = Object.fromEntries(
  ARC_SPECS.map((s) => [String(s.id), buildArcFeedback(s)]),
);

