/* Merged exports (real mainnet + arc demo). Interface unchanged.          */
/* ===================================================================== */

export const AGENTS: Agent[] = [...MAINNET_AGENTS, ...ARC_AGENTS];

export const FEEDBACK: Record<string, FeedbackEntry[]> = {
  ...MAINNET_FEEDBACK,
  ...ARC_FEEDBACK,
};

export function getAgent(id: string): Agent | undefined {
  return AGENTS.find((a) => a.agentId === id);
}

export function getFeedback(id: string): FeedbackEntry[] {
  return FEEDBACK[id] ?? [];
}

export const ALL_SKILLS: string[] = Array.from(
  new Set(AGENTS.flatMap((a) => a.skills)),
).sort();

